_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

uv0 = vUv;
mask = clamp01(-1+8*(GP(uv0).r));
vUv = (vUv-0.5)*(1+ 0.014*sin(323*vRadius-uTime*22)*pow(vRadius,6))+0.5;

dz.x = GB1(vUv+hor*4).r-GB1(vUv-hor*4).r;
dz.y = GB1(vUv+ver*4).r-GB1(vUv-ver*4).r;
dz*=1/GB2(vUv).r * (mask>0) * 0.3;

dzw.x = noise2(vUv+hor)-noise2(vUv-hor);
dzw.y = noise2(vUv+ver)-noise2(vUv-ver);

mcol = mix(mix(col2,col1,length(dz)*2),(1+col1.zxy)/2,sat(4*GetBlur1(vUv).g));

bcol = (1+sin(vec3(vAngle,vAngle+1,vAngle+2)))/2;
bcol = mix(bcol,col1,q2);

dz += 2*dzw * (texture(sampler_noise_hq,vUv).r>0.8);
dz += 3*dzw* (GB1(vUv).g>0.2);

uv2 = vUv+dzw;
ret = 8*GB3(uv2).b*bcol;;

bri = GetBlur1(vUv+-dz*.7).r-0.12;
ret = mix(ret,.25*bri, mask );;

ret += 0.08/length(sin(1*vUv+dz*6)-lpos) * mcol * mask;

dzb.x = 2*lum(GB1(vUv+hor*2).b)-2*lum(GB1(vUv-hor*2).b);
dzb.y = 2*lum(GB1(vUv+ver*2).b)-2*lum(GB1(vUv-ver*2).b);

float bmask = sat(GP(vUv).b*8);
ret = mix(ret, (ret+GB1(vUv).b)*(2+2/length(vUv*0.5+32*dzb*vnoise(vUv)))*bcol, bmask);

uv2 = vUv-lpos;
uv3 = (vUv-0.5)*0.9+.5+(lpos-0.5)*.2;
float k1=0.17/sqrt(length(uv2+dzw))*!mask;
ret +=  k1* sat(1-2*GB2(uv3).r*!mask)*q15*(1-vRadius)*col1; //lamp

ret +=  GB3(vUv-dz).b*16*mask*bcol; //blue mirr

shine = 0; radi = 0.95;
for (int n=1; n <= anz; n++)
{ shine += 1/anz*GetBlur2((uv0-.5)*radi+.5).b;
  radi -= 0.95/anz;}
ret += 32*shine*min(1,2*vRadius) *clamp01(sin(vAngle-q9))* bcol;
ret=1-exp(-1.8*ret);

//if (vUv.y>0.9) {if (vUv.x<0.5) {ret=col1;} else {ret=col2;}}

  fragColor = ret;
}
